const p=JSON.parse('{"key":"v-30367178","path":"/learningNote/Computer_Network/%E5%85%B3%E4%BA%8Eppp%E5%8D%8F%E8%AE%AE%E4%B8%8Epppoe%E5%8D%8F%E8%AE%AE.html","title":"ppp协议与pppoe协议","lang":"zh-CN","frontmatter":{"title":"ppp协议与pppoe协议","category":["Computer","Network","basic"]},"headers":[{"level":2,"title":"关于ppp协议与pppoe协议","slug":"关于ppp协议与pppoe协议","link":"#关于ppp协议与pppoe协议","children":[{"level":3,"title":"1、ppp（point to point）协议","slug":"_1、ppp-point-to-point-协议","link":"#_1、ppp-point-to-point-协议","children":[]},{"level":3,"title":"2、pppoe（ppp over Ethernet）协议","slug":"_2、pppoe-ppp-over-ethernet-协议","link":"#_2、pppoe-ppp-over-ethernet-协议","children":[]}]}],"git":{"createdTime":1692780329000,"updatedTime":1692780329000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":1.08,"words":323},"filePathRelative":"learningNote/Computer_Network/关于ppp协议与pppoe协议.md","localizedDate":"2023年8月23日","excerpt":"<h2> 关于ppp协议与pppoe协议</h2>\\n<h3> 1、ppp（point to point）协议</h3>\\n<p><strong>定义：</strong><a href=\\"https://baike.baidu.com/item/%E7%82%B9%E5%AF%B9%E7%82%B9%E5%8D%8F%E8%AE%AE/2991091?fromModule=lemma_inlink\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">点对点协议</a>（Point to Point Protocol，PPP）为在点对点连接上传输多协议数据包提供了一个标准方法。作为二层（数据链路层）协议，常用于拨号上网时客户端向服务器获取IP地址。PPP支持在各种物理类型的点对点串行线路上传输上层协议报文。</p>"}');export{p as data};
